function getNavbarNetworksForEnv(env: OrderlyEnv) {
  return env === "prod" ? NAVBAR_NETWORKS : TESTNET_NAVBAR_NETWORKS;
}

function getNetworkKeyForChainId(
  chainId: number | undefined,
  env: OrderlyEnv
): string | null {
  if (!chainId) return null;
  const matched = getNavbarNetworksForEnv(env).find(
    network => networkData[network.key]?.chainId === chainId
  );
  return matched?.key ?? null;
}

function normalizeNetworkForEnv(networkKey: string, env: OrderlyEnv): string {
  const allowedNetworks = getNavbarNetworksForEnv(env);
  return allowedNetworks.some(network => network.key === networkKey)
    ? networkKey
    : getDefaultNetworkForEnv(env);
}

