function abbreviate(str: string, start = 6, end = 4): string {
  if (!str || str.length <= start + end + 3) return str;
  return str.slice(0, start) + "..." + str.slice(-end);
}

function isApiLoginInputValid(value: string) {
  return /^[A-Za-z0-9]+$/.test(value.trim());
}

function getLoginRedirectUrl(): string {
  const profile = readStoredProfile();
  if (profile?.role === "ambassador" || profile?.brokerId === "ambassador")
    return "/distributor-dashboard";
  if (profile) return "/home";
  return "/onboarding";
}

function pickAnnouncement(rows: AnnouncementItem[]): AnnouncementItem | null {
  return rows.find(row => row.message?.trim() || row.url?.trim()) || null;
}

function getUpcomingMaintenance(
  systemInfo: SystemInfo | null
): SystemInfo["scheduled_maintenance"] | null {
  const maintenance = systemInfo?.scheduled_maintenance;
  if (!maintenance?.startTime) return null;
  const now = Date.now();
  const sevenDaysFromNow = now + 7 * 24 * 60 * 60 * 1000;
  if (maintenance.startTime >= now && maintenance.startTime <= sevenDaysFromNow)
    return maintenance;
  return null;
}

function formatMaintenanceWindow(
  maintenance: NonNullable<SystemInfo["scheduled_maintenance"]>
): string {
  const start = maintenance.startTime
    ? new Date(maintenance.startTime).toLocaleString()
    : "TBD";
  const end = maintenance.endTime
    ? new Date(maintenance.endTime).toLocaleString()
    : "TBD";
  return `Scheduled maintenance: ${start} - ${end}`;
}

function normalizeRedirectPath(value: string | null): string | null {
  if (!value || !value.startsWith("/")) return null;
  if (value.startsWith("//") || value.startsWith("/login")) return null;
  return value;
}

function getAbsoluteAnnouncementUrl(value?: string | null): string | null {
  if (!value) return null;
  try {
    const url = new URL(value);
    if (url.protocol !== "http:" && url.protocol !== "https:") return null;
    return url.hostname.includes(".") ? url.toString() : null;
  } catch {
    return null;
  }
}

function readStoredProfile(): {
  accountId?: string;
  brokerId?: string;
  builderName?: string;
  pathway?: "low-code" | "sdk";
  role?: string;
  graduated?: boolean;
  adminRegistered?: boolean;
  primaryLogo?: string | null;
  secondaryLogo?: string | null;
  logo?: string | null;
  orderlyKeyCreated?: boolean;
  adminType?: "eoa" | "multisig";
  multisigAddress?: string | null;
  multisigChainId?: number | null;
  createdAt?: string;
} | null {
  if (typeof window === "undefined") return null;
  const profileRaw = walletGetItem("orderlyProfile");
  if (!profileRaw) return null;
  try {
    return JSON.parse(profileRaw) as {
      accountId?: string;
      brokerId?: string;
      builderName?: string;
      pathway?: "low-code" | "sdk";
      role?: string;
      graduated?: boolean;
      adminRegistered?: boolean;
      primaryLogo?: string | null;
      secondaryLogo?: string | null;
      logo?: string | null;
      orderlyKeyCreated?: boolean;
      adminType?: "eoa" | "multisig";
      multisigAddress?: string | null;
      multisigChainId?: number | null;
      createdAt?: string;
    };
  } catch {
    return null;
  }
}

function waitForUiPaint(): Promise<void> {
  if (typeof window === "undefined") return Promise.resolve();
  return new Promise(resolve => {
    window.requestAnimationFrame(() => window.setTimeout(resolve, 0));
  });
}

function getAccountId(address: string, brokerId: string) {
  return keccak256(
    AbiCoder.defaultAbiCoder().encode(
      ["address", "bytes32"],
      [address, solidityPackedKeccak256(["string"], [brokerId])]
    )
  );
}

function hasCompletedAmbassadorName(name?: string | null): boolean {
  const trimmed = name?.trim();
  return Boolean(trimmed && trimmed !== AMBASSADOR_PLACEHOLDER_NAME);
}

